// Extract products array from Shopify response
const products = $input.first().json?.products || [];

if (!products.length) {
  return [];
}

// Filter: must have title + at least one image
const valid = products.filter(p =>
  p.title &&
  p.images?.length > 0 &&
  parseFloat(p.variants?.[0]?.price || '0') >= 1
);

return valid.map(p => ({
  json: {
    productId: String(p.id),
    title: p.title,
    description: (p.body_html || '')
      .replace(/<[^>]+>/g, '')
      .replace(/\s+/g, ' ')
      .trim()
      .substring(0, 450),
    price: `$${parseFloat(p.variants?.[0]?.price || '0').toFixed(2)}`,
    rawPrice: parseFloat(p.variants?.[0]?.price || '0'),
    productUrl: `https://${p.vendor?.toLowerCase().replace(/\s+/g,'-')}.myshopify.com/products/${p.handle}`,
    imageUrl: p.images[0]?.src || '',
    allImages: p.images.slice(0, 3).map(i => i.src),
    tags: (typeof p.tags === 'string' ? p.tags.split(',') : p.tags || []).map(t => t.trim()).filter(Boolean).slice(0, 6),
    vendor: p.vendor || 'Store',
    productType: p.product_type || ''
  }
}));

// Inject platform value so Switch can route all 3 branches
const item = $input.first().json;
return [
  { json: { ...item, platform: 'instagram' } },
  { json: { ...item, platform: 'facebook' } },
  { json: { ...item, platform: 'twitter' } }
];
